import{_ as e,o,c as a,ag as r}from"./chunks/framework.OsDJF_Ea.js";const s="/docs/modules/porta-sampler.png",g=JSON.parse('{"title":"PortaSampler","description":"","frontmatter":{},"headers":[],"relativePath":"modules/porta-sampler.md","filePath":"modules/porta-sampler.md"}'),n={name:"modules/porta-sampler.md"};function d(i,t,l,h,c,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="portasampler" tabindex="-1">PortaSampler <a class="header-anchor" href="#portasampler" aria-label="Permalink to &quot;PortaSampler&quot;">​</a></h1><p><strong>Category:</strong> Sound Sources</p><p>8-slot sample recorder and player. Records sounds from the audio input using threshold detection with pre-roll transient capture, then plays them back from gate triggers, MIDI notes, or hardware buttons. Each slot supports up to 3 velocity layers. Three modes: one-shot, loop, velocity-layer. Kits can be saved to and loaded from the SD card. Auto-mapped across 3 hardware banks for record, mix, and trim/trigger control.</p><img src="'+s+'" alt="porta-sampler module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>audioIn</strong> (audio)</td><td>Audio input for recording. Connect from a Piezo Input, Stereo In, or any audio source.</td></tr><tr><td><strong>midi_in</strong></td><td>Optional. Connect any output from a MIDIIn node here to scope this PortaSampler to that MIDIIn&#39;s channel. Without this cable, all 8 slots already respond to MIDI notes 36-43 (GM drum mapping) from every connected source -- hardware DIN, USB, BLE -- with real velocity driving gain and layer selection. This cable is a reference only (no audio-rate CV flows over it); it only matters if you need channel isolation, e.g. two PortaSamplers in one patch listening to different MIDI channels.</td></tr><tr><td><strong>gate1</strong>..<strong>gate8</strong></td><td>Trigger gates for slots 1-8. Rising edge starts playback. Gates 5-8 are hidden by default; show them with <code>show_gates_5_8</code>.</td></tr><tr><td><strong>pitch_cv</strong></td><td>Pitch CV affecting all voices. 0.5 = unity, higher = faster playback.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>mixL</strong> (audio)</td><td>Left main mix.</td></tr><tr><td><strong>mixR</strong> (audio)</td><td>Right main mix.</td></tr><tr><td><strong>auxL</strong> (audio)</td><td>Left aux send.</td></tr><tr><td><strong>auxR</strong> (audio)</td><td>Right aux send.</td></tr></tbody></table><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>bank</code></td><td>1</td><td>Hardware bank assignment (auto-claimed). PortaSampler consumes 3 consecutive banks.</td></tr><tr><td><code>threshold</code></td><td>0.47</td><td>Recording threshold 0-1. Recording auto-starts when the input crosses this and auto-stops when it falls back below.</td></tr><tr><td><code>max_length</code></td><td>1.7</td><td>Maximum recording duration in seconds. Inspector-only -- no hardware pot. Default is the full sample pool (~2.5MB uncontested) divided evenly across all 8 slots.</td></tr><tr><td><code>master_level</code></td><td>0.8</td><td>Master output level.</td></tr><tr><td><code>kit_folder</code></td><td>&quot;&quot;</td><td>SD folder used for kit save/load.</td></tr><tr><td><code>show_gates_5_8</code></td><td>false</td><td>Show gate inputs 5-8 in the patcher UI.</td></tr></tbody></table><h2 id="hardware-mapping" tabindex="-1">Hardware Mapping <a class="header-anchor" href="#hardware-mapping" aria-label="Permalink to &quot;Hardware Mapping&quot;">​</a></h2><p>PortaSampler claims <strong>3 consecutive banks</strong>:</p><ul><li><strong>Bank 1 -- Record:</strong> Pot1 = threshold, Pot2 = pitch, Pot3 = mode (one-shot/loop), Pot4 = volume. Btn1 = arm/trigger/stop (short press), clear (long press, 500ms+ -- wipes the recording and leaves the slot idle; press Btn1 again to re-arm, same as any other empty slot). Btn2 = reverse, Btn3 = previous slot, Btn4 = next slot.</li><li><strong>Bank 2 -- Trim:</strong> Pot1 = start, Pot2 = end (relative to Start, not the absolute sample position -- 0 sits right at Start, full winds out to the end of the sample, so the pot&#39;s full travel stays useful no matter where Start is set), Pot3 = pan, Pot4 = aux send. Btn1 = trigger the selected slot, Btn2 = mute the selected slot, Btn3/Btn4 = previous/next slot.</li><li><strong>Bank 3 -- Filter / Trigger:</strong> Pot1 = destructive filter cutoff, Pot2 = filter type (HP/BP/LP). Pot3-4 unassigned. Btn1 = trigger the selected slot, Btn2 = apply the filter to the selected slot, Btn3/Btn4 = previous/next slot.</li></ul><p>Btn1 (trigger) and Btn3/Btn4 (previous/next slot) are identical across all three banks -- only Btn2 differs (reverse / mute / apply filter). Every button acts on whichever slot is currently selected, not a fixed per-button slot index.</p><p><code>max_length</code> (max recording duration, in seconds) has no hardware pot -- set it from the Inspector. Default is 1.7s (the full pool divided evenly across 8 slots); raise it for a longer single recording at the cost of less room for the other slots.</p><h3 id="bank-1-led-feedback-screen-free-workflow" tabindex="-1">Bank 1 LED feedback (screen-free workflow) <a class="header-anchor" href="#bank-1-led-feedback-screen-free-workflow" aria-label="Permalink to &quot;Bank 1 LED feedback (screen-free workflow)&quot;">​</a></h3><ul><li><strong>Btn1</strong>: flashes red whenever the selected slot is empty (freshly navigated to, freshly armed, or freshly cleared) -- unambiguous &quot;ready to capture&quot; indicator with no screen. Solid red while actively recording. Dark once the slot holds a take (Pot1 carries that status instead).</li><li><strong>Btn2</strong>: solid red = reverse is on for the selected slot, dark = forward. Persistent state, not a momentary press flash.</li><li><strong>Pot1</strong>: while the slot has no recording yet, shows a live input-level meter -- green above the record threshold, red below -- so the threshold can be set and the desired sound previewed by eye. Once the slot holds a take, switches to status: solid blue = has data, green = this slot is currently playing.</li><li><strong>Slot-position indicator</strong>: pressing Btn3 (Prev) or Btn4 (Next) lights <em>only</em> the LED for the newly-selected slot, full red, for 1 second, overriding every other Bank 1 LED&#39;s normal meaning for that window -- Pot1=slot1, Pot2=slot2, Pot3=slot3, Pot4=slot4, Btn1=slot5, Btn2=slot6, Btn3=slot7, Btn4=slot8. Repeated presses keep extending the window, so browsing quickly through slots tracks live and only holds on the final one for the last second.</li></ul><h3 id="bank-2-bank-3-led-feedback" tabindex="-1">Bank 2 / Bank 3 LED feedback <a class="header-anchor" href="#bank-2-bank-3-led-feedback" aria-label="Permalink to &quot;Bank 2 / Bank 3 LED feedback&quot;">​</a></h3><ul><li><strong>Bank 2 Btn2 (mute)</strong>: solid red = the selected slot is muted, dark = not muted. Persistent state, not a momentary press flash -- same reasoning as Bank 1&#39;s reverse LED.</li><li><strong>Bank 3 Btn2 (apply filter)</strong>: plain momentary press-flash -- destructively applying the filter is a one-shot action, there&#39;s no ongoing state to show.</li><li><strong>Btn1/Btn3/Btn4 on both banks</strong>: plain momentary press-feedback (superseded almost immediately by the slot-position indicator, which fires on the same Btn3/Btn4 press).</li></ul><h3 id="kit-browsing-from-the-panel" tabindex="-1">Kit browsing from the panel <a class="header-anchor" href="#kit-browsing-from-the-panel" aria-label="Permalink to &quot;Kit browsing from the panel&quot;">​</a></h3><p>Beyond saving/loading kits over serial (<code>PSSAVE</code> / <code>PSLOAD</code>), the 7 most recently saved kits can be browsed and loaded from the panel alone:</p><ol><li>On Bank 1, hold both bank-navigation buttons together for 1 second to enter kit-select mode. The 8 Bank 1 pot/button LEDs repurpose to show 8 positions -- Blank (position 0, wipes to an empty kit) plus the 7 most recent kits by save time -- magenta on the pots, red on the buttons (buttons only have red available on this hardware batch). Only the currently-highlighted position is lit; it fast-flashes if that position is Blank or empty, solid if it&#39;s a real kit.</li><li>Use Btn3/Btn4 to move between positions.</li><li>Confirm and load the highlighted kit either by holding both bank-navigation buttons together again, or by leaving it alone -- it auto-confirms after a short idle period, so browsing doesn&#39;t require a second deliberate gesture to commit.</li></ol><p>If the <code>preview_enabled</code> param is on (Inspector-only, off by default), each occupied kit auto-plays its slots in sequence while highlighted -- one-shots play once then advance to the next occupied slot, loops play for roughly 2 seconds then advance -- so a kit can be auditioned by ear before committing. Preview uses a small dedicated buffer, completely separate from the currently-loaded kit&#39;s own sample data, so browsing never disturbs what&#39;s actually loaded until you confirm.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Connect a Piezo Input or Stereo In to the <code>audioIn</code> input. Switch to Bank 1, set the threshold with Pot1, and press Btn1 to arm. Make a sound and recording starts automatically when the input crosses the threshold, then stops when it dies away (or after <code>max_length</code> seconds -- raise it in the Inspector if your source runs long). Navigate slots with Btn3 / Btn4 (the same on every bank). Trigger the selected slot with Btn1 on Bank 2 or Bank 3, mute it with Bank 2&#39;s Btn2, or destructively apply the filter with Bank 3&#39;s Btn2. Kits can be saved and loaded over the serial console using the <code>PSSAVE</code> and <code>PSLOAD</code> commands, or browsed straight from the panel (see Kit browsing above). Slots 1-8 can be triggered via gate inputs (enable <code>show_gates_5_8</code> for gates 5-8) or MIDI notes 36-43 -- MIDI works with no cable at all by default. Only add a MIDIIn node and wire it into <code>midi_in</code> if you need this instance to ignore MIDI on other channels (e.g. running two PortaSamplers side by side, each on its own channel).</p><p><strong>Loop mode retrigger:</strong> for a slot in Loop mode, triggering it again while it&#39;s already playing stops it instead of starting a second overlapping voice -- press to start, press again to stop, from any bank&#39;s trigger button (Bank 1 Btn1, or Bank 2/3&#39;s Btn1). MIDI is the exception: a loop-mode slot follows the note&#39;s gate -- note-on starts it, note-off stops it, matching how CV gate inputs already behave. One-shot and velocity-layer slots are unaffected by any of this; retriggering those always plays another voice.</p><h2 id="midi-cc-automation-fixed-per-slot-bank-independent" tabindex="-1">MIDI CC automation (fixed per-slot, bank-independent) <a class="header-anchor" href="#midi-cc-automation-fixed-per-slot-bank-independent" aria-label="Permalink to &quot;MIDI CC automation (fixed per-slot, bank-independent)&quot;">​</a></h2><p>Each of the 8 slots has 5 dedicated MIDI CC numbers -- Pitch, Pan, Volume, Start, End -- that target that <em>specific</em> slot directly, regardless of which bank is currently selected on the hardware. This is separate from the bank-pot CC system (CC 20-48, only live while its bank is showing): these CCs always apply, so an external sequencer can automate a slot continuously while the hardware pots/buttons are being used for something else entirely, with no conflict.</p><p>CC number = <code>50 + (slot - 1) x 5 + param offset</code> (param offset: Pitch=0, Pan=1, Volume=2, Start=3, End=4):</p><table tabindex="0"><thead><tr><th>Slot</th><th>Pitch</th><th>Pan</th><th>Volume</th><th>Start</th><th>End</th></tr></thead><tbody><tr><td>1</td><td>CC50</td><td>CC51</td><td>CC52</td><td>CC53</td><td>CC54</td></tr><tr><td>2</td><td>CC55</td><td>CC56</td><td>CC57</td><td>CC58</td><td>CC59</td></tr><tr><td>3</td><td>CC60</td><td>CC61</td><td>CC62</td><td>CC63</td><td>CC64</td></tr><tr><td>4</td><td>CC65</td><td>CC66</td><td>CC67</td><td>CC68</td><td>CC69</td></tr><tr><td>5</td><td>CC70</td><td>CC71</td><td>CC72</td><td>CC73</td><td>CC74</td></tr><tr><td>6</td><td>CC75</td><td>CC76</td><td>CC77</td><td>CC78</td><td>CC79</td></tr><tr><td>7</td><td>CC80</td><td>CC81</td><td>CC82</td><td>CC83</td><td>CC84</td></tr><tr><td>8</td><td>CC85</td><td>CC86</td><td>CC87</td><td>CC88</td><td>CC89</td></tr></tbody></table><p>Accepted over hardware MIDI DIN, USB MIDI, and BLE MIDI -- whichever is highest wins if more than one source sends the same CC. A slot&#39;s normal pot-driven value (from Bank 1/2 when that slot happens to be hardware-selected) is left alone until its automation CC has actually been received at least once, so adding this doesn&#39;t silently reset volume/pan/start on slots you aren&#39;t automating. Once a CC has been touched, it keeps overriding that parameter for that slot until the device reboots.</p><p>This is well suited to per-trig parameter locks on something like an Elektron Digitakt: dedicate one CC lane per parameter on the track whose 8 trigs already fire the 8 note-triggers, and each trig can carry its own pitch/pan/volume/start/end alongside its note -- turning a short one-shot into something closer to a chromatically-playable, loop-scrubbable instrument, sequenced entirely from outside the Porta.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',33)])])}const m=e(n,[["render",d]]);export{g as __pageData,m as default};
